// DOM elements
const menuGrid = document.getElementById("menuGrid");
const chips = document.querySelectorAll(".chip");
const searchInput = document.getElementById("searchInput");
const yearEl = document.getElementById("year");

let currentFilter = "all";
let currentQuery = "";
let cart = [];

const cartCount = document.getElementById("cartCount");
const alertTitle = document.getElementById("alertTitle");
const alertItems = document.getElementById("alertItems");
const alertTotal = document.getElementById("alertTotal");
const alertActions = document.getElementById("alertActions");
const alertModal = document.getElementById("alertModal");

// Render menu items
function renderMenu() {
  const filtered = MENU_ITEMS.filter(item => {
    const matchesCategory = currentFilter === "all" || item.category === currentFilter;
    const matchesQuery = item.title.toLowerCase().includes(currentQuery) ||
                         item.desc.toLowerCase().includes(currentQuery);
    return matchesCategory && matchesQuery;
  });

  menuGrid.innerHTML = filtered.map((item, index) => `
    <div class="card scroll-animate" style="--delay:${index * 0.1}s" data-id="${item.id}">
      <img src="${item.image}" alt="${item.title}" class="card-img" onclick="showAlert('${item.image}')"/>
      <div class="card-body">
        <h3>${item.title}</h3>
        <p>${item.desc}</p>
        <p><strong>$${item.price.toFixed(2)}</strong></p>
        <button class="btn btn-primary" onclick="addToCart('${item.id}')">Add to Cart</button>
      </div>
    </div>
  `).join("");

  handleScroll(); // animate new items
}

// Overlay functions
function showAlert(src) {
  document.getElementById('alertImg').src = src;
  document.getElementById('overlay').style.display = 'flex';
}
function closeAlert() {
  document.getElementById('overlay').style.display = 'none';
}

// Event listeners
chips.forEach(chip => {
  chip.addEventListener("click", () => {
    chips.forEach(c => c.classList.remove("active"));
    chip.classList.add("active");
    currentFilter = chip.dataset.filter;
    renderMenu();
  });
});
searchInput.addEventListener("input", () => {
  currentQuery = searchInput.value.toLowerCase();
  renderMenu();
});

// Footer year
yearEl.textContent = new Date().getFullYear();

// Cart functions
function addToCart(id) {
  const item = MENU_ITEMS.find(i => i.id === id);
  cart.push(item);
  cartCount.textContent = cart.length;
  showCartAlert();
}

function showCartAlert() {
  if (cart.length === 0) {
    alertTitle.textContent = "Your Cart";
    alertItems.innerHTML = "<p>Your cart is empty.</p>";
    alertTotal.textContent = "";
    alertActions.innerHTML = `<button class="close-btn" onclick="closeModal()">Close</button>`;
  } else {
    alertTitle.textContent = "Your Cart";
    alertItems.innerHTML = cart.map((i, index) => `
      <div class="cart-item">
        <img src="${i.image}" alt="${i.title}">
        <span>${i.title} - $${i.price.toFixed(2)}</span>
        <button class="delete-btn" onclick="deleteItem(${index})">Delete</button>
      </div>
    `).join("");
    const total = cart.reduce((sum, i) => sum + i.price, 0);
    alertTotal.textContent = `Total: $${total.toFixed(2)}`;
       alertActions.innerHTML = `
      <button class="checkout-btn" onclick="checkout()">Checkout</button>
      <button class="clear-btn" onclick="clearCart()">Clear All</button>
      <button class="close-btn" onclick="closeModal()">Close</button>
    `;
  }
  alertModal.style.display = "flex";
}

function deleteItem(index) {
  cart.splice(index, 1);
  cartCount.textContent = cart.length;
  showCartAlert();
}

function checkout() {
  if (cart.length === 0) {
    alertTitle.textContent = "Your Cart";
    alertItems.innerHTML = "<p>Your cart is empty.</p>";
    alertTotal.textContent = "";
    alertActions.innerHTML = `<button class="close-btn" onclick="closeModal()">OK</button>`;
  } else {
    const total = cart.reduce((sum, i) => sum + i.price, 0);
    alertTitle.textContent = "Checkout Successful!";
    alertItems.innerHTML = "<p>Thank you for your order.</p>";
    alertTotal.textContent = `Total Paid: $${total.toFixed(2)}`;
    cart = [];
    cartCount.textContent = 0;
    alertActions.innerHTML = `<button class="close-btn" onclick="closeModal()">OK</button>`;
  }
}

function clearCart() {
  cart = [];
  cartCount.textContent = 0;
  showCartAlert();
}

function closeModal() {
  alertModal.style.display = "none";
}
// Scroll spy for nav links
const sections = document.querySelectorAll("section");
const navLinks = document.querySelectorAll(".nav-links a");

window.addEventListener("scroll", () => {
  let current = "";
  sections.forEach(section => {
    const sectionTop = section.offsetTop - 80;
    if (window.scrollY >= sectionTop) {
      current = section.getAttribute("id");
    }
  });

  navLinks.forEach(link => {
    link.classList.remove("active");
    if (link.getAttribute("href").includes(current)) {
      link.classList.add("active");
    }
  });
});

// Scroll animation
function handleScroll() {
  const animatedEls = document.querySelectorAll('.scroll-animate');
  animatedEls.forEach((el, index) => {
    const rect = el.getBoundingClientRect();
    if (rect.top < window.innerHeight - 100) {
      el.classList.add('show');
      // stagger delay for grid items
      if (el.closest('.grid')) {
        el.style.setProperty('--delay', `${index * 0.1}s`);
      }
    }
  });
}

window.addEventListener('scroll', handleScroll);

// Initialize
renderMenu();
handleScroll(); // run once on load